-- Migration : 035
-- Description: Daily predictions generated by prediction_engine.py
-- Created    : 2026-04-04
--
-- Populated by: prediction_engine.py (runs daily after market close)
-- Key design:
--   • prediction_date = date the prediction was generated (T)
--   • target_date     = date of the expected move (T+1 by default)
--   • confidence_pct  = scaled score 0–100 (only predictions >= 60 are inserted)
--   • status lifecycle: 'open' → 'hit' | 'miss' | 'expired'
--     - 'expired': target_date passed but OHLCV not yet available (holiday/weekend)
--   • features_json: snapshot of today's feature vector used to match the pattern
--     (important for post-mortem analysis — allows replay without re-querying)
--   • Only patterns with stars >= 3 generate predictions
--   • One row per (prediction_date × symbol × pattern_id) — a symbol can match
--     multiple patterns on the same day; each gets its own prediction row

CREATE TABLE IF NOT EXISTS analysis.predictions
(
    prediction_date     Date,
    target_date         Date,
    symbol              String,
    market              String,
    pattern_id          String,
    stars               UInt8,
    confidence_pct      Float64,            -- 0–100; only >= 60 inserted
    predicted_direction String,             -- 'UP' | 'DOWN'
    predicted_min_pct   Float64,            -- minimum expected move % (e.g. 2.0)
    features_json       String DEFAULT '{}',-- snapshot of feature vector at prediction time
    status              String DEFAULT 'open',  -- 'open' | 'hit' | 'miss' | 'expired'
    created_at          DateTime DEFAULT now(),
    version             UInt64 DEFAULT 0
)
ENGINE = ReplacingMergeTree(version)
ORDER BY (prediction_date, symbol, pattern_id)
